// Parse WhatsApp messages with loop prevention
const input = $input.all()[0].json;
let output = {};

// ⚠️ UPDATE THESE to match your WhatsApp Business phone number ID and display number
const BOT_NUMBERS = ['YOUR_PHONE_NUMBER_ID', 'YOUR_DISPLAY_PHONE_NUMBER'];

const isBot = (number) => {
  if (!number) return false;
  const cleanNumber = String(number).replace(/\D/g, '');
  return BOT_NUMBERS.some(botNum => 
    cleanNumber.includes(botNum.replace(/\D/g, ''))
  );
};

// Process INCOMING messages only
if (input.messages && input.messages[0]) {
  const message = input.messages[0];
  const contact = input.contacts?.[0] || {};

  // Ignore bot's own messages
  if (isBot(message.from)) {
    return {
      json: {
        eventType: 'outgoing',
        skipProcessing: true,
        receivedAt: new Date().toISOString()
      }
    };
  }

  output = {
    eventType: 'message',
    skipProcessing: false,
    from: message.from,
    messageId: message.id,
    timestamp: message.timestamp,
    name: contact.profile?.name || 'Unknown',
    messageBody: message.text?.body || '',
    messageType: message.type || 'text',
    waId: contact.wa_id || message.from,
    phoneNumberId: input.metadata?.phone_number_id || '',
    receivedAt: new Date(parseInt(message.timestamp) * 1000).toISOString()
  };
}
// Process STATUS updates (skip)
else if (input.statuses && input.statuses[0]) {
  return {
    json: {
      eventType: 'status',
      skipProcessing: true,
      receivedAt: new Date().toISOString()
    }
  };
}
// Unknown format
else {
  return {
    json: {
      eventType: 'unknown',
      skipProcessing: true,
      receivedAt: new Date().toISOString()
    }
  };
}

return { json: output };

