const messageData = $node["🔧 Parse WhatsApp Message"].json;
const rawAiOutput = $json;

let aiOutput = {};

function extractJSON(str) {
  if (typeof str !== 'string') return null;
  let cleaned = str.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const match = cleaned.match(/\{[\s\S]*"intent"\s*:[\s\S]*\}/);
    if (match) {
      try { return JSON.parse(match[0]); } catch (e2) { return null; }
    }
    return null;
  }
}

function findAIResponse(obj, depth = 0) {
  if (depth > 5 || !obj || typeof obj !== 'object') return null;
  if (obj.intent && typeof obj.intent === 'string') return obj;

  const props = ['output', 'text', 'message', 'content', 'response', 'result', 'data', 'json', 'kwargs', 'lc_kwargs'];

  for (const prop of props) {
    if (obj[prop] !== undefined) {
      if (typeof obj[prop] === 'string') {
        const parsed = extractJSON(obj[prop]);
        if (parsed && parsed.intent) return parsed;
      } else if (typeof obj[prop] === 'object') {
        const found = findAIResponse(obj[prop], depth + 1);
        if (found) return found;
      }
    }
  }

  for (const key of Object.keys(obj)) {
    if (props.includes(key)) continue;
    const val = obj[key];
    if (typeof val === 'string' && val.includes('"intent"')) {
      const parsed = extractJSON(val);
      if (parsed && parsed.intent) return parsed;
    } else if (typeof val === 'object' && val !== null) {
      const found = findAIResponse(val, depth + 1);
      if (found) return found;
    }
  }
  return null;
}

try {
  if (rawAiOutput && rawAiOutput.intent) {
    aiOutput = rawAiOutput;
  } else {
    const found = findAIResponse(rawAiOutput);
    if (found) aiOutput = found;
  }

  if (!aiOutput.intent) {
    const fullString = JSON.stringify(rawAiOutput);
    const parsed = extractJSON(fullString);
    if (parsed && parsed.intent) aiOutput = parsed;
  }

  if (!aiOutput.intent && typeof rawAiOutput === 'string') {
    const parsed = extractJSON(rawAiOutput);
    if (parsed && parsed.intent) aiOutput = parsed;
  }
} catch (error) {}

const validIntents = ['hot_lead', 'warm_lead', 'support', 'spam', 'needs_qualification'];

if (!aiOutput.intent || !validIntents.includes(aiOutput.intent)) {
  if (!aiOutput.intent) {
    aiOutput = {
      intent: 'needs_qualification',
      confidence: 0.5,
      reason: 'Could not parse AI response - defaulting to qualification',
      hasEnoughInfo: false,
      missingInfo: ['parsing failed - needs manual review'],
      nextQuestion: 'Hi! Thanks for reaching out 😊 How can I help you today?'
    };
  } else {
    aiOutput.intent = 'needs_qualification';
  }
}

const result = {
  from: messageData.from || '',
  name: messageData.name || '',
  messageBody: messageData.messageBody || '',
  messageId: messageData.messageId || '',
  messageType: messageData.messageType || 'text',
  timestamp: messageData.timestamp || '',
  receivedAt: messageData.receivedAt || '',
  waId: messageData.waId || '',
  skipProcessing: messageData.skipProcessing || false,
  phoneNumberId: messageData.phoneNumberId || '',
  intent: aiOutput.intent,
  confidence: parseFloat(aiOutput.confidence) || 0,
  reason: aiOutput.reason || 'No reason provided',
  hasEnoughInfo: aiOutput.hasEnoughInfo === true,
  missingInfo: Array.isArray(aiOutput.missingInfo) ? aiOutput.missingInfo : [],
  nextQuestion: aiOutput.nextQuestion || '',
  processedAt: new Date().toISOString(),
  model: 'your-ai-model'
};

return { json: result };

